// Import required modules
const fs = require('fs');
const path = require('path');

// Load existing test file
const testPath = path.join(__dirname, '../data/challenge/day-01/daily-test.json');
const existing = JSON.parse(fs.readFileSync(testPath, 'utf8'));

console.log(`Existing test questions: ${existing.questions.length}`);

// ─────────────────────────────────────────────────────────────
// 200 NEW TEST QUESTIONS (IDs 201-400)
// Types: mcq, translation, fill-blank, true-false, error-detection, reorder
// Difficulty: easy, medium, hard
// Topics: SVO, pronouns, articles, simple present, frequency adverbs,
//         question words, possessives, negatives, vocabulary, idioms
// ─────────────────────────────────────────────────────────────

const newQuestions = [
  // ── MEDIUM-HARD MCQ (201-240) ───────────────────────────────
  { id: 201, type: "mcq", question: "Which sentence uses the correct article?", options: ["She is a honest woman.", "She is an honest woman.", "She is the honest woman.", "She is honest woman."], correct: "B", explanation: "'Honest' starts with a vowel sound /ɒ/ (H is silent), so we use 'an'. 'An honest man, an heir, an hour' — remember these!", difficulty: "medium", marks: 1 },
  { id: 202, type: "mcq", question: "Choose the correct sentence:", options: ["He doesn't knows the answer.", "He don't know the answer.", "He doesn't know the answer.", "He not know the answer."], correct: "C", explanation: "He (3rd person singular) → doesn't + base verb 'know'. Never 'doesn't knows'.", difficulty: "medium", marks: 1 },
  { id: 203, type: "translation", question: "Translate: 'क्या तुम्हें English पसंद है?'", options: ["Do you likes English?", "Are you like English?", "Do you like English?", "Does you like English?"], correct: "C", explanation: "You के साथ 'Do' + base verb 'like' (no -s). Simple Present question form.", difficulty: "medium", marks: 1 },
  { id: 204, type: "fill-blank", question: "The children ___ very happy today.", options: ["is", "am", "are", "be"], correct: "C", explanation: "'Children' is plural, so we use 'are'. Be verb forms: I am, you are, he/she/it is, we/they are.", difficulty: "easy", marks: 1 },
  { id: 205, type: "mcq", question: "Identify the error: 'I am having a car.'", options: ["I am", "having", "a", "car"], correct: "B", explanation: "'Have' when showing possession is a stative verb — not used in continuous. Correct: 'I have a car.'", difficulty: "medium", marks: 1 },
  { id: 206, type: "mcq", question: "Which is correct? '___ it rain in Mumbai in July?'", options: ["Do", "Does", "Is", "Has"], correct: "B", explanation: "'It' (3rd person singular) → 'Does'. 'Does it rain?' is the correct question form.", difficulty: "medium", marks: 1 },
  { id: 207, type: "translation", question: "Translate: 'मैं हर सोमवार gym नहीं जाता।'", options: ["I am not going gym every Monday.", "I don't go to the gym every Monday.", "I doesn't go to gym every Monday.", "I not go gym every Monday."], correct: "B", explanation: "I + don't + base verb. 'Gym' = specific place needs 'the'. 'Every Monday' = frequency.", difficulty: "medium", marks: 1 },
  { id: 208, type: "mcq", question: "Which word is a frequency adverb?", options: ["quickly", "always", "very", "far"], correct: "B", explanation: "Frequency adverbs show HOW OFTEN: always, usually, often, sometimes, rarely, never. 'Quickly' = manner, 'very' = degree, 'far' = place.", difficulty: "easy", marks: 1 },
  { id: 209, type: "fill-blank", question: "'She ___ to school by bus.' Complete with correct form of 'go'.", options: ["go", "goes", "going", "gone"], correct: "B", explanation: "She (3rd person singular) → go + es = goes. Simple Present rules.", difficulty: "easy", marks: 1 },
  { id: 210, type: "mcq", question: "Which sentence is correct?", options: ["We is ready for the exam.", "We are ready for the exam.", "We am ready for the exam.", "We be ready for the exam."], correct: "B", explanation: "'We' always takes 'are' with be verbs. I=am, He/She/It=is, You/We/They=are.", difficulty: "easy", marks: 1 },
  { id: 211, type: "mcq", question: "What question word asks about reason?", options: ["Where", "When", "Why", "What"], correct: "C", explanation: "'Why' = reason/cause (क्यों). Where=place, When=time, What=thing.", difficulty: "easy", marks: 1 },
  { id: 212, type: "translation", question: "Translate: 'वह कहाँ रहता है?'", options: ["Where does he lives?", "Where is he live?", "Where does he live?", "Where he does live?"], correct: "C", explanation: "WH question: Where + does + subject + base verb? He (singular) = does. 'Live' (base form, no -s with does).", difficulty: "medium", marks: 1 },
  { id: 213, type: "fill-blank", question: "'I ___ a student.' (am/is/are)", options: ["is", "am", "are", "be"], correct: "B", explanation: "I always takes 'am'. This is the most basic English grammar rule.", difficulty: "easy", marks: 1 },
  { id: 214, type: "mcq", question: "Choose the correct possessive adjective for 'they':", options: ["his", "her", "their", "its"], correct: "C", explanation: "They → Their (possessive adjective). 'Their car', 'their house'. Don't confuse with 'there' or 'they're'.", difficulty: "easy", marks: 1 },
  { id: 215, type: "error-detection", question: "Find the error: 'My friend and me go to gym everyday.'", options: ["My friend", "and me", "go to gym", "everyday"], correct: "B", explanation: "'Me' as subject is wrong. 'My friend and I go to the gym every day.' Subject = 'I', not 'me'. Also: 'the gym', 'every day' (two words).", difficulty: "hard", marks: 2 },
  { id: 216, type: "mcq", question: "Which sentence has CORRECT word order?", options: ["Always he is late.", "He is late always.", "He always is late.", "He is always late."], correct: "D", explanation: "With 'be' verbs, frequency adverbs come AFTER the verb: 'He is always late.' With action verbs, frequency adverbs come BEFORE: 'He always comes late.'", difficulty: "medium", marks: 1 },
  { id: 217, type: "translation", question: "Translate: 'क्या वह एक doctor है?'", options: ["Is he a doctor?", "Does he a doctor?", "Is he an doctor?", "He is a doctor?"], correct: "A", explanation: "Yes/No question with 'be' verb: Is/Am/Are + subject? 'He is a doctor' → 'Is he a doctor?'", difficulty: "easy", marks: 1 },
  { id: 218, type: "fill-blank", question: "I ___ English every day. It is helping me a lot.", options: ["study", "studies", "studying", "studied"], correct: "A", explanation: "I + base verb (no -s). Simple Present for habits/routines.", difficulty: "easy", marks: 1 },
  { id: 219, type: "mcq", question: "Which article is used before 'MBA'?", options: ["a", "an", "the", "no article"], correct: "B", explanation: "'MBA' is pronounced 'em-bee-ay' — starts with vowel sound /e/, so 'an MBA'. Letters pronounced with vowel sounds use 'an': an MBA, an MLA, an HR manager.", difficulty: "hard", marks: 2 },
  { id: 220, type: "true-false", question: "'He go to school by bus every day.' — This sentence is grammatically correct.", options: ["True", "False", "Partially true", "Cannot say"], correct: "B", explanation: "False. 'He' is 3rd person singular → 'goes' not 'go'. Correct: 'He goes to school by bus every day.'", difficulty: "easy", marks: 1 },
  { id: 221, type: "mcq", question: "What does 'seldom' mean?", options: ["हमेशा", "कभी-कभी", "बहुत कम बार", "कभी नहीं"], correct: "C", explanation: "'Seldom' = बहुत कम, rarely. Frequency order: always > usually > often > sometimes > rarely/seldom > never.", difficulty: "medium", marks: 1 },
  { id: 222, type: "translation", question: "Translate: 'हम रोज़ रात 10 बजे सोते हैं।'", options: ["We sleep at 10 PM every night.", "We sleeps at 10 PM every night.", "We are sleep at 10 PM every night.", "We sleeping at 10 PM every night."], correct: "A", explanation: "We + base verb (sleep). 'At 10 PM' = specific time uses 'at'.", difficulty: "easy", marks: 1 },
  { id: 223, type: "fill-blank", question: "'___ you understand everything so far?' Complete:", options: ["Are", "Is", "Do", "Does"], correct: "C", explanation: "You + Do (auxiliary for present simple questions with non-be verbs).", difficulty: "easy", marks: 1 },
  { id: 224, type: "mcq", question: "Identify the subject in: 'The tall man in the blue suit speaks English.'", options: ["tall", "man", "The tall man in the blue suit", "speaks"], correct: "C", explanation: "The full subject = 'The tall man in the blue suit' — the entire noun phrase including modifiers.", difficulty: "hard", marks: 2 },
  { id: 225, type: "mcq", question: "Which is correct: 'The news ___ very interesting.'", options: ["are", "is", "am", "were"], correct: "B", explanation: "'News' looks plural but is singular in grammar. Always use 'is': The news is, the information is, the furniture is.", difficulty: "hard", marks: 2 },
  { id: 226, type: "error-detection", question: "Find the error: 'She don't go to office on Sundays.'", options: ["She", "don't", "go to", "on Sundays"], correct: "B", explanation: "'She' (3rd person singular) → 'doesn't' (not 'don't'). Correct: 'She doesn't go to office on Sundays.'", difficulty: "medium", marks: 1 },
  { id: 227, type: "translation", question: "Translate: 'मुझे coffee पसंद नहीं है।'", options: ["I not like coffee.", "I don't like coffee.", "I doesn't like coffee.", "I am not like coffee."], correct: "B", explanation: "I + don't + base verb (like). 'I don't like coffee' = standard Simple Present negative.", difficulty: "easy", marks: 1 },
  { id: 228, type: "mcq", question: "Choose the correct form: 'My parents ___ in Delhi for 10 years.'", options: ["live", "lives", "is living", "are living"], correct: "A", explanation: "Parents = They (plural) + base verb 'live'. Simple Present for permanent facts/current states.", difficulty: "medium", marks: 1 },
  { id: 229, type: "fill-blank", question: "He ___ to music while working. (listen)", options: ["listen", "listens", "listening", "listened"], correct: "B", explanation: "He (singular) → listen + s = listens. Verbs ending in consonant-n + s.", difficulty: "easy", marks: 1 },
  { id: 230, type: "mcq", question: "Which WH word asks about method or manner?", options: ["What", "When", "How", "Which"], correct: "C", explanation: "'How' asks about method, manner, or condition. How do you learn English? How are you?", difficulty: "easy", marks: 1 },
  { id: 231, type: "mcq", question: "'The committee ___ meeting right now.' Which is correct?", options: ["is", "are", "am", "be"], correct: "A", explanation: "In American English, collective nouns (committee, team, government) are singular → 'is'. British English allows both. For professional use, prefer 'is'.", difficulty: "hard", marks: 2 },
  { id: 232, type: "translation", question: "Translate: 'तुम कितनी बार English में सोचते हो?'", options: ["How often do you think in English?", "How many you think in English?", "How often are you thinking in English?", "How often you think in English?"], correct: "A", explanation: "Frequency question: How often + do + subject + base verb? 'Think' is stative — avoid continuous.", difficulty: "hard", marks: 2 },
  { id: 233, type: "fill-blank", question: "'___ is the capital of India?' Choose correct WH word.", options: ["Who", "Whose", "What", "Which"], correct: "C", explanation: "'What' asks about things, places, or ideas. 'Who' = person. 'Which' = specific choice from options.", difficulty: "easy", marks: 1 },
  { id: 234, type: "mcq", question: "Which sentence is grammatically correct?", options: ["Sheela and Meena is my classmates.", "Sheela and Meena are my classmate.", "Sheela and Meena are my classmates.", "Sheela and Meena am my classmates."], correct: "C", explanation: "Two subjects joined by 'and' → plural verb 'are'. Noun 'classmate' → plural 'classmates' for two people.", difficulty: "medium", marks: 1 },
  { id: 235, type: "mcq", question: "Choose the reflexive pronoun for 'she':", options: ["herself", "himself", "itself", "oneself"], correct: "A", explanation: "Reflexive pronouns: myself, yourself, himself, herself, itself, ourselves, yourselves, themselves.", difficulty: "medium", marks: 1 },
  { id: 236, type: "translation", question: "Translate: 'यह उसकी किताब है। वह उसकी है।'", options: ["This is her book. It is hers.", "This is hers book. It is her.", "This is her book. It is her.", "This is hers book. It is hers."], correct: "A", explanation: "Possessive adjective before noun = 'her book'. Possessive pronoun alone = 'hers'. No noun after possessive pronoun.", difficulty: "hard", marks: 2 },
  { id: 237, type: "mcq", question: "Identify the correct usage of 'whose':", options: ["Whose is this bag?", "Whose bag is this?", "Whose bag this is?", "Both A and B are correct"], correct: "D", explanation: "Both 'Whose is this bag?' and 'Whose bag is this?' are correct. Both ask about ownership.", difficulty: "hard", marks: 2 },
  { id: 238, type: "fill-blank", question: "'The police ___ arrived at the scene.' (has/have)", options: ["has", "have", "is", "are"], correct: "B", explanation: "'Police' is always plural in grammar → 'have'. Like 'people' (always plural), 'cattle', 'crew'.", difficulty: "hard", marks: 2 },
  { id: 239, type: "mcq", question: "Which option correctly completes: 'I brush my teeth ___ day.'", options: ["all", "every", "each and every", "whole"], correct: "B", explanation: "'Every day' = each day without exception. 'All day' = throughout the entire day. 'Every day' (two words) ≠ 'everyday' (adjective).", difficulty: "medium", marks: 1 },
  { id: 240, type: "true-false", question: "'An university offers many courses.' — This is grammatically correct.", options: ["True", "False", "Partially true", "Cannot say"], correct: "B", explanation: "False. 'University' starts with a consonant sound /j/ (yoo-ni-ver-si-ty), so use 'a'. Correct: 'A university'. Same for 'a uniform', 'a European'.", difficulty: "hard", marks: 2 },

  // ── ERROR DETECTION (241-260) ───────────────────────────────
  { id: 241, type: "error-detection", question: "Find the error: 'She always comes to office by the metro.'", options: ["She always", "comes to", "office by", "the metro"], correct: "D", explanation: "In general usage, 'metro' doesn't need 'the' here. Correct: 'She always comes to office by metro.' (or 'by the metro' is also acceptable in some varieties). However 'by metro' = standard.", difficulty: "medium", marks: 1 },
  { id: 242, type: "error-detection", question: "Find the error: 'He is more taller than his brother.'", options: ["He is", "more taller", "than", "his brother"], correct: "B", explanation: "'More taller' is a double comparative — wrong. Use either 'taller' (short adjective + -er) OR 'more tall' (not standard). Correct: 'He is taller than his brother.'", difficulty: "hard", marks: 2 },
  { id: 243, type: "error-detection", question: "Find the error: 'I have visited Paris last year.'", options: ["I have visited", "Paris", "last year", "No error"], correct: "A", explanation: "'Last year' is a specific past time → use Simple Past, not Present Perfect. Correct: 'I visited Paris last year.' Present Perfect = indefinite past (I have visited Paris before).", difficulty: "hard", marks: 2 },
  { id: 244, type: "error-detection", question: "Find the error: 'Neither Ram nor his friends was present.'", options: ["Neither Ram", "nor his friends", "was present", "No error"], correct: "C", explanation: "With 'neither...nor', the verb agrees with the subject CLOSEST to it. 'Friends' (plural) → 'were'. Correct: '...nor his friends were present.'", difficulty: "hard", marks: 2 },
  { id: 245, type: "error-detection", question: "Find the error: 'She speaks English very good.'", options: ["She speaks", "English", "very", "good"], correct: "D", explanation: "'Good' is an adjective but 'speaks' is a verb — we need an adverb. 'Well' is the adverb form. Correct: 'She speaks English very well.'", difficulty: "medium", marks: 1 },
  { id: 246, type: "error-detection", question: "Find the error: 'The informations are available online.'", options: ["The informations", "are", "available", "online"], correct: "A", explanation: "'Information' is uncountable — no 's' ever. Correct: 'The information is available online.' Like: advice, furniture, luggage.", difficulty: "hard", marks: 2 },
  { id: 247, type: "error-detection", question: "Find the error: 'I am agree with your decision.'", options: ["I am", "agree with", "your", "decision"], correct: "A", explanation: "'Agree' is a stative verb — not used with 'am/is/are'. Correct: 'I agree with your decision.' Never 'I am agree'.", difficulty: "medium", marks: 1 },
  { id: 248, type: "error-detection", question: "Find the error: 'Do you know where does he live?'", options: ["Do you know", "where does", "he live", "No error"], correct: "B", explanation: "In indirect/embedded questions, we don't use question word order. Correct: 'Do you know where he lives?' (NOT 'where does he live' inside).", difficulty: "hard", marks: 2 },
  { id: 249, type: "error-detection", question: "Find the error: 'She suggested me to take the job.'", options: ["She suggested", "me to", "take the job", "No error"], correct: "B", explanation: "'Suggest' cannot be followed by object + infinitive. Correct: 'She suggested that I take the job' OR 'She suggested taking the job.'", difficulty: "hard", marks: 2 },
  { id: 250, type: "error-detection", question: "Find the error: 'He is one of the best player in the team.'", options: ["He is one of", "the best", "player in", "the team"], correct: "C", explanation: "'One of the' is always followed by a plural noun. Correct: 'one of the best players in the team.'", difficulty: "hard", marks: 2 },
  { id: 251, type: "error-detection", question: "Find the error: 'I look forward to meet you.'", options: ["I look", "forward to", "meet you", "No error"], correct: "C", explanation: "'Look forward to' is followed by a gerund (verb+ing), not infinitive. Correct: 'I look forward to meeting you.'", difficulty: "hard", marks: 2 },
  { id: 252, type: "error-detection", question: "Find the error: 'The teacher, along with the students, are going for a picnic.'", options: ["The teacher", "along with the students", "are going", "for a picnic"], correct: "C", explanation: "'Along with' doesn't change the subject. Subject = 'The teacher' (singular) → 'is'. Correct: 'The teacher, along with the students, is going...'", difficulty: "hard", marks: 2 },
  { id: 253, type: "error-detection", question: "Find the error: 'She is too much intelligent.'", options: ["She is", "too much", "intelligent", "No error"], correct: "B", explanation: "'Too much' is used with nouns/uncountable. With adjectives, use 'too': 'She is too intelligent.' 'Too much noise' (noun) vs. 'too loud' (adjective).", difficulty: "hard", marks: 2 },
  { id: 254, type: "error-detection", question: "Find the error: 'Everyday I wake up at 6 AM.'", options: ["Everyday", "I wake up", "at 6 AM", "No error"], correct: "A", explanation: "'Everyday' (one word) = adjective meaning 'ordinary' (everyday English). 'Every day' (two words) = each day. Correct: 'Every day I wake up at 6 AM.'", difficulty: "medium", marks: 1 },
  { id: 255, type: "error-detection", question: "Find the error: 'Both of the student passed the exam.'", options: ["Both of", "the student", "passed", "the exam"], correct: "B", explanation: "'Both' refers to two → plural noun required. Correct: 'Both of the students passed the exam.'", difficulty: "medium", marks: 1 },
  { id: 256, type: "error-detection", question: "Find the error: 'I am born in Patna in 2000.'", options: ["I am born", "in Patna", "in 2000", "No error"], correct: "A", explanation: "Birth is a one-time past event → Simple Past or Passive Past. Correct: 'I was born in Patna in 2000.' 'Am born' = grammatically wrong.", difficulty: "medium", marks: 1 },
  { id: 257, type: "error-detection", question: "Find the error: 'He speaks very fastly.'", options: ["He speaks", "very", "fastly", "No error"], correct: "C", explanation: "'Fastly' is not a word. 'Fast' is already both adjective AND adverb. Correct: 'He speaks very fast.' Like: hard, early, late, high, low.", difficulty: "medium", marks: 1 },
  { id: 258, type: "error-detection", question: "Find the error: 'I have a lot of works to do.'", options: ["I have", "a lot of", "works to do", "No error"], correct: "C", explanation: "'Work' (job/tasks) is uncountable — no 's'. Correct: 'I have a lot of work to do.' 'Works' = artworks, literary works (different meaning).", difficulty: "hard", marks: 2 },
  { id: 259, type: "error-detection", question: "Find the error: 'She is very much beautiful.'", options: ["She is", "very much", "beautiful", "No error"], correct: "B", explanation: "'Very much' is used with verbs (I like it very much). With adjectives, use 'very': 'She is very beautiful.' OR 'She is very much a perfectionist' (before nouns used as predicate).", difficulty: "hard", marks: 2 },
  { id: 260, type: "error-detection", question: "Find the error: 'He has been went to the market.'", options: ["He has been", "went to", "the market", "No error"], correct: "B", explanation: "'Has been' + past participle = passive OR 'has been + V-ing' = perfect continuous. Correct: 'He has gone to the market' (present perfect). 'Went' = simple past.", difficulty: "hard", marks: 2 },

  // ── REORDER/REARRANGEMENT (261-280) ─────────────────────────
  { id: 261, type: "reorder", question: "Arrange to make a correct sentence: [school / every / to / goes / she / morning]", options: ["She goes to school every morning.", "She every morning goes to school.", "Every morning she to school goes.", "She goes every morning school to."], correct: "A", explanation: "Correct SVO order: Subject (She) + Verb (goes) + Place (to school) + Time (every morning). Time expressions usually go at the end.", difficulty: "medium", marks: 1 },
  { id: 262, type: "reorder", question: "Arrange: [not / does / like / she / spicy food]", options: ["She not like does spicy food.", "She does not like spicy food.", "Does she not like spicy food?", "She not does like spicy food."], correct: "B", explanation: "Negative: Subject + does not + base verb + object. 'Does not like' = 'doesn't like'.", difficulty: "medium", marks: 1 },
  { id: 263, type: "reorder", question: "Arrange: [you / English / speak / do / fluently?]", options: ["Do you speak English fluently?", "You do speak English fluently?", "Do you fluently speak English?", "Fluently do you speak English?"], correct: "A", explanation: "Question order: Do/Does + subject + base verb + object + adverb. Manner adverbs usually come after the object.", difficulty: "medium", marks: 1 },
  { id: 264, type: "reorder", question: "Arrange: [is / the / of / what / capital / France?]", options: ["What is the capital of France?", "What the capital is of France?", "What is France capital of the?", "Of France what is capital the?"], correct: "A", explanation: "WH question: What + is + the + noun + prepositional phrase? Standard WH question pattern.", difficulty: "medium", marks: 1 },
  { id: 265, type: "reorder", question: "Arrange: [my / always / lunch / brings / mother / home]", options: ["My mother always brings lunch home.", "Always my mother lunch home brings.", "My mother brings always home lunch.", "Lunch always brings my mother home."], correct: "A", explanation: "Frequency adverb 'always' + main verb. Object (lunch) + place (home) at end. Subject first.", difficulty: "medium", marks: 1 },
  { id: 266, type: "reorder", question: "Arrange: [an / Apple / is / very / apple / healthy / a]", options: ["An apple a day is very healthy.", "A apple is very healthy.", "An apple is a very healthy.", "An apple is very healthy."], correct: "D", explanation: "Subject (An apple) + is + adjective (very healthy). 'An' before vowel sound 'a'.", difficulty: "medium", marks: 1 },
  { id: 267, type: "reorder", question: "Arrange: [never / late / is / he / meetings / for]", options: ["He is never late for meetings.", "Never he is late for meetings.", "He never late is for meetings.", "He is late never for meetings."], correct: "A", explanation: "Frequency adverb 'never' comes after 'be' verb: He is never... Standard position.", difficulty: "medium", marks: 1 },
  { id: 268, type: "reorder", question: "Arrange: [many / how / have / you / do / books?]", options: ["How many books do you have?", "How many do you have books?", "Do you have how many books?", "How many books you have?"], correct: "A", explanation: "WH quantity: How many + noun + do/does + subject + verb? Standard question order.", difficulty: "medium", marks: 1 },
  { id: 269, type: "reorder", question: "Arrange: [she / teacher / becomes / a / wants / to]", options: ["She wants to become a teacher.", "She wants become to a teacher.", "To become a teacher she wants.", "She become wants a to teacher."], correct: "A", explanation: "'Want' + to + infinitive. 'Become' = infinitive (no 'to' after, 'to' comes from 'want to').", difficulty: "medium", marks: 1 },
  { id: 270, type: "reorder", question: "Arrange: [company / does / the / in / where / he / work?]", options: ["Where does he work in the company?", "In which company does he work?", "Where in the company does he work?", "In what company he does work?"], correct: "B", explanation: "'In which company does he work?' = most natural way to ask. WH + noun + auxiliary + subject + verb.", difficulty: "hard", marks: 2 },
  { id: 271, type: "reorder", question: "Arrange: [English / learning / is / everyone / for / important]", options: ["Learning English is important for everyone.", "English learning is for everyone important.", "For everyone English learning important is.", "Everyone is important for English learning."], correct: "A", explanation: "Subject (Learning English/Gerund phrase) + is + adjective + for + everyone. Gerund as subject takes singular verb.", difficulty: "medium", marks: 1 },
  { id: 272, type: "reorder", question: "Arrange: [bus / by / usually / comes / the / she / office / to]", options: ["She usually comes to the office by bus.", "Usually she to office comes by the bus.", "She comes usually to office by bus.", "By bus she usually comes the office to."], correct: "A", explanation: "Subject + frequency adverb + verb + place + manner. 'Usually' before main verb 'comes'.", difficulty: "medium", marks: 1 },
  { id: 273, type: "reorder", question: "Arrange: [are / these / mine / books / not]", options: ["These books are not mine.", "These not are books mine.", "Books these are not mine.", "Mine are not these books."], correct: "A", explanation: "Subject (These books) + be verb (are) + negative (not) + predicate (mine). Possessive pronoun at end.", difficulty: "medium", marks: 1 },
  { id: 274, type: "reorder", question: "Arrange: [I / for / do / know / a / not / you / living / what]", options: ["I do not know what you do for a living.", "What I do not know you do for a living.", "I know not what do you do for living.", "What do you do for a living I do not know."], correct: "A", explanation: "Main clause (I do not know) + embedded question (what you do for a living). No inversion in embedded questions!", difficulty: "hard", marks: 2 },
  { id: 275, type: "reorder", question: "Arrange: [exercises / how / he / often / does?]", options: ["How often does he exercise?", "How often he exercises?", "Does he exercise how often?", "How he often does exercise?"], correct: "A", explanation: "How often + does + subject + base verb? 'Exercise' (base form) NOT 'exercises' (because 'does' is already auxiliary).", difficulty: "medium", marks: 1 },
  { id: 276, type: "reorder", question: "Arrange: [my / is / sister / a / doctor / younger]", options: ["My younger sister is a doctor.", "My sister younger is a doctor.", "A doctor is my younger sister.", "Is my younger sister a doctor?"], correct: "A", explanation: "Adjective order: possessive (my) + age (younger) + noun (sister). Subject first in statement.", difficulty: "medium", marks: 1 },
  { id: 277, type: "reorder", question: "Arrange: [English / does / in / what / mean / 'जुगाड़'?]", options: ["What does 'jugaad' mean in English?", "In English what does 'jugaad' mean?", "What 'jugaad' means in English?", "Does 'jugaad' what in English mean?"], correct: "A", explanation: "WH question: What + does + subject + verb + in English? Standard question pattern.", difficulty: "medium", marks: 1 },
  { id: 278, type: "reorder", question: "Arrange: [have / you / why / studied / not / today?]", options: ["Why have you not studied today?", "Why you have not studied today?", "Have you why not studied today?", "Why not have you studied today?"], correct: "A", explanation: "WH question with have/has: Why + have + subject + not + past participle? Note: 'Why haven't you studied today?' also correct.", difficulty: "hard", marks: 2 },
  { id: 279, type: "reorder", question: "Arrange: [will / she / doctor / become / great / a]", options: ["She will become a great doctor.", "She will a great doctor become.", "A great doctor she will become.", "Will she become great a doctor?"], correct: "A", explanation: "Future: Subject + will + base verb + object (with articles and adjectives).", difficulty: "medium", marks: 1 },
  { id: 280, type: "reorder", question: "Arrange: [the / tallest / Qutub Minar / is / in / building / Delhi]", options: ["Qutub Minar is the tallest building in Delhi.", "The tallest building Qutub Minar is in Delhi.", "Qutub Minar the tallest is building in Delhi.", "In Delhi Qutub Minar is tallest building the."], correct: "A", explanation: "Superlative: The + superlative + noun. Subject (Qutub Minar) + is + the tallest building + in Delhi.", difficulty: "medium", marks: 1 },

  // ── VOCABULARY IN CONTEXT (281-310) ─────────────────────────
  { id: 281, type: "mcq", question: "Choose the correct meaning of 'verbose':", options: ["very brief", "using too many words", "speaking clearly", "silent"], correct: "B", explanation: "'Verbose' = using too many words, wordy. 'Concise' = opposite (brief and clear). Professional writing should be concise, not verbose.", difficulty: "hard", marks: 2 },
  { id: 282, type: "mcq", question: "What does 'profound' mean?", options: ["shallow", "very deep or serious", "confused", "ordinary"], correct: "B", explanation: "'Profound' = very deep, serious, or intense. 'A profound impact', 'a profound thinker'. From Latin 'profundus' = deep.", difficulty: "hard", marks: 2 },
  { id: 283, type: "fill-blank", question: "She is very ___. She always helps others. (kind/unkind/cruel/rude)", options: ["unkind", "kind", "cruel", "rude"], correct: "B", explanation: "'Kind' = helpful, caring. Context: 'always helps others' = positive trait = kind.", difficulty: "easy", marks: 1 },
  { id: 284, type: "mcq", question: "Which word means 'to make something better'?", options: ["worsen", "improve", "decrease", "fail"], correct: "B", explanation: "'Improve' = make better. 'Worsen' = make worse. 'Improve your skills' = develop, enhance, upgrade.", difficulty: "easy", marks: 1 },
  { id: 285, type: "mcq", question: "What is a synonym of 'intelligent'?", options: ["dull", "slow", "clever", "confused"], correct: "C", explanation: "Synonyms of 'intelligent': clever, smart, bright, sharp, brilliant, gifted. Antonyms: dull, foolish, slow.", difficulty: "easy", marks: 1 },
  { id: 286, type: "fill-blank", question: "He never gives up. He is very ___.", options: ["lazy", "persistent", "careless", "forgetful"], correct: "B", explanation: "'Persistent' = continuing despite difficulties. 'Never gives up' = persistent, determined, resilient.", difficulty: "medium", marks: 1 },
  { id: 287, type: "mcq", question: "What does 'mandatory' mean?", options: ["optional", "required by law or rules", "temporary", "expensive"], correct: "B", explanation: "'Mandatory' = compulsory, obligatory, required. 'Mandatory attendance' = you must attend. Opposite: 'optional', 'voluntary'.", difficulty: "medium", marks: 1 },
  { id: 288, type: "mcq", question: "Choose the antonym of 'transparent':", options: ["clear", "honest", "opaque", "visible"], correct: "C", explanation: "'Transparent' = can be seen through, open. Antonym: 'opaque' = cannot see through, secretive. 'Translucent' = partially transparent.", difficulty: "medium", marks: 1 },
  { id: 289, type: "fill-blank", question: "I study English every ___. (day/week/always)", options: ["always", "day", "never", "sometimes"], correct: "B", explanation: "'Every day' = each day. 'Always' doesn't fit after 'every'. Common pattern: every + time period (day, week, month, year).", difficulty: "easy", marks: 1 },
  { id: 290, type: "mcq", question: "What does 'genuine' mean?", options: ["fake", "expensive", "real and authentic", "ordinary"], correct: "C", explanation: "'Genuine' = real, authentic, sincere. 'Genuine leather' = real leather. 'Genuine smile' = sincere, not fake.", difficulty: "medium", marks: 1 },
  { id: 291, type: "mcq", question: "Which word fits: 'She gave a ___ speech that moved everyone to tears.'", options: ["boring", "powerful", "quiet", "confusing"], correct: "B", explanation: "'Powerful' speech = moved people to tears. Context clue: 'moved everyone to tears' = emotional, impactful = powerful.", difficulty: "medium", marks: 1 },
  { id: 292, type: "fill-blank", question: "The doctor gave him a ___ for the medicine.", options: ["recipe", "prescription", "permission", "ticket"], correct: "B", explanation: "'Prescription' = doctor's written instruction for medicine. 'Recipe' = cooking. Common confusion for Hindi speakers.", difficulty: "medium", marks: 1 },
  { id: 293, type: "mcq", question: "Choose the word that means 'to make someone feel less confident':", options: ["encourage", "motivate", "discourage", "support"], correct: "C", explanation: "'Discourage' = make someone lose confidence or desire. 'Encourage' = opposite. Prefix 'dis-' often creates antonyms.", difficulty: "medium", marks: 1 },
  { id: 294, type: "mcq", question: "What does 'approximately' mean?", options: ["exactly", "roughly/about", "definitely", "never"], correct: "B", explanation: "'Approximately' = around, about, roughly. 'Approximately 50 people attended' = around 50. Shorter form: 'approx.'", difficulty: "medium", marks: 1 },
  { id: 295, type: "fill-blank", question: "He is very ___. He never tells lies.", options: ["dishonest", "fake", "honest", "rude"], correct: "C", explanation: "'Honest' = truthful, never lies. Context clue: 'never tells lies' directly defines the answer.", difficulty: "easy", marks: 1 },
  { id: 296, type: "mcq", question: "Which word means 'to get better after being sick'?", options: ["deteriorate", "recover", "worsen", "fall"], correct: "B", explanation: "'Recover' = get better after illness or difficulty. 'Recovery' = the process. 'Full recovery' = completely better.", difficulty: "easy", marks: 1 },
  { id: 297, type: "mcq", question: "Choose the correct meaning of 'fluent':", options: ["confused", "able to speak smoothly and easily", "speaking very slowly", "making many mistakes"], correct: "B", explanation: "'Fluent' = speaking smoothly, naturally, without hesitation. 'Fluent in English' = can speak English naturally.", difficulty: "easy", marks: 1 },
  { id: 298, type: "fill-blank", question: "The news report says ___ 5 million people attended the rally.", options: ["exactly", "approximately", "definitely", "clearly"], correct: "B", explanation: "'Approximately' = the number is not exact but around that figure. News reports often use 'approximately' or 'around'.", difficulty: "medium", marks: 1 },
  { id: 299, type: "mcq", question: "What is the opposite of 'confident'?", options: ["bold", "brave", "insecure", "proud"], correct: "C", explanation: "Antonym of 'confident' = 'insecure', 'uncertain', 'timid', 'hesitant'. 'Confident' = sure of yourself.", difficulty: "easy", marks: 1 },
  { id: 300, type: "mcq", question: "Which word fits: 'The project was ___ — it took 3 months longer than planned.'", options: ["delayed", "advanced", "successful", "cancelled"], correct: "A", explanation: "'Delayed' = took longer than planned. Context clue: '3 months longer than planned' = delayed, behind schedule.", difficulty: "medium", marks: 1 },

  // ── IDIOMS & PHRASES (301-320) ──────────────────────────────
  { id: 301, type: "mcq", question: "What does 'hit the nail on the head' mean?", options: ["to injure someone", "to be exactly right", "to start working", "to miss the point"], correct: "B", explanation: "'Hit the nail on the head' = say or do exactly the right thing. 'You hit the nail on the head!' = You're exactly right!", difficulty: "medium", marks: 1 },
  { id: 302, type: "mcq", question: "What does 'break a leg' mean?", options: ["to injure your leg", "good luck", "to dance", "to fail"], correct: "B", explanation: "'Break a leg' = good luck (especially in theatre/performing). It's ironic/superstitious — saying 'good luck' was thought to bring bad luck!", difficulty: "medium", marks: 1 },
  { id: 303, type: "mcq", question: "What does 'cost an arm and a leg' mean?", options: ["physical injury", "very expensive", "very cheap", "paying in instalments"], correct: "B", explanation: "'Cost an arm and a leg' = very expensive. 'That phone costs an arm and a leg' = it's very costly.", difficulty: "medium", marks: 1 },
  { id: 304, type: "mcq", question: "What does 'under the weather' mean?", options: ["outside in bad weather", "feeling unwell/sick", "confused", "very happy"], correct: "B", explanation: "'Under the weather' = not feeling well, slightly ill. 'I'm feeling a bit under the weather today' = I'm not well.", difficulty: "medium", marks: 1 },
  { id: 305, type: "mcq", question: "What does 'bite the bullet' mean?", options: ["to shoot", "to eat", "to endure something difficult", "to be angry"], correct: "C", explanation: "'Bite the bullet' = face a difficult or unpleasant situation bravely. 'Just bite the bullet and go to the dentist!' = be brave and do it.", difficulty: "medium", marks: 1 },
  { id: 306, type: "mcq", question: "What does 'the ball is in your court' mean?", options: ["sports reference", "it's your turn to take action/decide", "you won", "play better"], correct: "B", explanation: "'The ball is in your court' = it's your turn to make a decision or take action. Used in business/negotiations.", difficulty: "medium", marks: 1 },
  { id: 307, type: "mcq", question: "What does 'burn bridges' mean?", options: ["to start fires", "to damage relationships permanently", "to build connections", "to cross a bridge"], correct: "B", explanation: "'Burn bridges' = destroy relationships with people. 'Don't burn bridges when you leave a job' = maintain good relationships.", difficulty: "medium", marks: 1 },
  { id: 308, type: "mcq", question: "What does 'on the fence' mean?", options: ["sitting outside", "unable to decide", "very confident", "in danger"], correct: "B", explanation: "'On the fence' = undecided, not committed to either side. 'I'm still on the fence about which job to take' = I can't decide.", difficulty: "medium", marks: 1 },
  { id: 309, type: "mcq", question: "What does 'spill the beans' mean?", options: ["to cook food", "to reveal a secret", "to waste food", "to be angry"], correct: "B", explanation: "'Spill the beans' = accidentally or deliberately reveal secret information. 'Who spilled the beans about the surprise party?'", difficulty: "easy", marks: 1 },
  { id: 310, type: "mcq", question: "What does 'once in a blue moon' mean?", options: ["during full moon", "very rarely", "at nighttime", "every month"], correct: "B", explanation: "'Once in a blue moon' = very rarely, almost never. 'He visits us once in a blue moon' = very rarely.", difficulty: "easy", marks: 1 },
  { id: 311, type: "mcq", question: "What does 'bite off more than you can chew' mean?", options: ["eating too much", "taking on more than you can handle", "being greedy about food", "making promises"], correct: "B", explanation: "'Bite off more than you can chew' = take on more responsibility than you can manage. 'Don't bite off more than you can chew with 5 projects at once!'", difficulty: "medium", marks: 1 },
  { id: 312, type: "mcq", question: "What does 'hit the ground running' mean?", options: ["to start running", "to start working effectively immediately", "to fall down", "to escape"], correct: "B", explanation: "'Hit the ground running' = begin something energetically and effectively from the very start. Common business phrase.", difficulty: "medium", marks: 1 },
  { id: 313, type: "mcq", question: "What does 'the tip of the iceberg' mean?", options: ["the most important part", "only a small visible part of a larger problem", "the beginning", "the end"], correct: "B", explanation: "'The tip of the iceberg' = a small, visible part of a much larger, hidden problem. 'This delay is just the tip of the iceberg.'", difficulty: "medium", marks: 1 },
  { id: 314, type: "mcq", question: "What does 'think outside the box' mean?", options: ["think about boxes", "think conventionally", "think creatively and differently", "arrange boxes"], correct: "C", explanation: "'Think outside the box' = think creatively, beyond conventional approaches. Very common in business and interviews.", difficulty: "easy", marks: 1 },
  { id: 315, type: "mcq", question: "What does 'get the ball rolling' mean?", options: ["start playing football", "initiate/start something", "finish a task", "make things faster"], correct: "B", explanation: "'Get the ball rolling' = initiate something, start a process. 'Let's get the ball rolling on this new project.'", difficulty: "easy", marks: 1 },
  { id: 316, type: "mcq", question: "What does 'back to square one' mean?", options: ["returning home", "starting over from the beginning", "playing chess", "reaching the goal"], correct: "B", explanation: "'Back to square one' = have to start again from the beginning after a failure. 'The plan failed, so we're back to square one.'", difficulty: "medium", marks: 1 },
  { id: 317, type: "mcq", question: "What does 'a blessing in disguise' mean?", options: ["a hidden curse", "something that seems bad but turns out good", "a surprise gift", "a secret plan"], correct: "B", explanation: "'A blessing in disguise' = something that seems bad at first but turns out to be good. 'Losing that job was a blessing in disguise — I found a better one!'", difficulty: "medium", marks: 1 },
  { id: 318, type: "mcq", question: "What does 'cut corners' mean?", options: ["to cut in a corner", "do something poorly to save time/money", "to be precise", "turn a corner"], correct: "B", explanation: "'Cut corners' = do something improperly to save time or money, reducing quality. 'Don't cut corners when learning English — do it properly!'", difficulty: "medium", marks: 1 },
  { id: 319, type: "mcq", question: "What does 'go the extra mile' mean?", options: ["walk more", "do more than required", "travel far", "be slow"], correct: "B", explanation: "'Go the extra mile' = make more effort than expected. 'She always goes the extra mile for her customers.' = gives exceptional service.", difficulty: "easy", marks: 1 },
  { id: 320, type: "mcq", question: "What does 'kill two birds with one stone' mean?", options: ["animal cruelty", "achieve two things with one action", "be violent", "impossible task"], correct: "B", explanation: "'Kill two birds with one stone' = accomplish two things at the same time with one effort. Very efficient!", difficulty: "easy", marks: 1 },

  // ── ADVANCED GRAMMAR (321-360) ──────────────────────────────
  { id: 321, type: "mcq", question: "Which is correct: 'He is interested in ___ English.'", options: ["learn", "to learn", "learning", "learned"], correct: "C", explanation: "'Interested in' + gerund (verb-ing). Like all prepositions: 'in', 'at', 'by', 'for', 'on' → followed by gerund.", difficulty: "medium", marks: 1 },
  { id: 322, type: "mcq", question: "Choose the correct sentence with 'used to':", options: ["I used to play cricket when I am young.", "I used to play cricket when I was young.", "I use to play cricket when I was young.", "I used to played cricket when I was young."], correct: "B", explanation: "'Used to' + base verb describes past habits that no longer happen. Context: past → 'when I was young'. 'Used to play' (not 'used to played').", difficulty: "hard", marks: 2 },
  { id: 323, type: "mcq", question: "Which sentence correctly uses 'can'?", options: ["She can to swim well.", "She can swimming well.", "She can swims well.", "She can swim well."], correct: "D", explanation: "Modal verbs (can, could, will, would...) + base verb (no 'to', no -s, no -ing). 'She can swim' = correct.", difficulty: "medium", marks: 1 },
  { id: 324, type: "translation", question: "Translate: 'उसे English बोलनी नहीं आती थी।'", options: ["She could not speak English.", "She didn't could speak English.", "She couldn't speak English.", "Both A and C are correct"], correct: "D", explanation: "'Could not' and 'couldn't' are the same — both correct. Past ability: could (positive), couldn't/could not (negative).", difficulty: "hard", marks: 2 },
  { id: 325, type: "mcq", question: "Which is correct: 'I wish I ___ fly.'", options: ["can", "could", "will", "would"], correct: "B", explanation: "'Wish' + past form expresses hypothetical desire. 'I wish I could fly' = I can't fly but wish I could. 'Wish + could' for present/future wishes.", difficulty: "hard", marks: 2 },
  { id: 326, type: "mcq", question: "Choose the correct: 'If I ___ you, I would study more.'", options: ["am", "was", "were", "be"], correct: "C", explanation: "Second conditional: If I were (not was) you = hypothetical. 'Were' is used for all persons in formal/written English in conditional clauses.", difficulty: "hard", marks: 2 },
  { id: 327, type: "mcq", question: "Which is the correct passive form of 'She teaches English'?", options: ["English is taught by her.", "English taught by her.", "English is teaching by her.", "English teaches by her."], correct: "A", explanation: "Passive: Object + is/are + past participle + by + subject. 'English is taught by her.' Simple present passive.", difficulty: "hard", marks: 2 },
  { id: 328, type: "translation", question: "Translate: 'मुझे यह काम करना है।'", options: ["I have to do this work.", "I should do this work.", "I must to do this work.", "I am having to do this work."], correct: "A", explanation: "'Have to' = obligation/necessity. 'I have to do' = it's necessary. 'Should' = advice. 'Must' = stronger. Here: 'have to' is best.", difficulty: "medium", marks: 1 },
  { id: 329, type: "mcq", question: "Choose the correct: 'By the time she arrives, I ___ the work.'", options: ["will finish", "will have finished", "finish", "am finishing"], correct: "B", explanation: "Future Perfect: 'will have + past participle'. Action completed before another future action. 'By the time' = signal for Future Perfect.", difficulty: "hard", marks: 2 },
  { id: 330, type: "mcq", question: "Which sentence is in the Present Perfect?", options: ["She was eating lunch.", "She eats lunch every day.", "She has eaten lunch already.", "She will eat lunch soon."], correct: "C", explanation: "Present Perfect: has/have + past participle. 'Has eaten' = present perfect. Used for past actions with present relevance.", difficulty: "medium", marks: 1 },
  { id: 331, type: "mcq", question: "Choose the correct relative pronoun: 'The book ___ I bought yesterday is excellent.'", options: ["who", "whom", "which", "whose"], correct: "C", explanation: "'Which' for things. 'Who' for people. 'The book which I bought' OR 'The book that I bought'. For things, use 'which' or 'that'.", difficulty: "medium", marks: 1 },
  { id: 332, type: "translation", question: "Translate: 'वह 3 घंटे से पढ़ रही है।'", options: ["She is studying for 3 hours.", "She has been studying for 3 hours.", "She was studying for 3 hours.", "She studies for 3 hours."], correct: "B", explanation: "'3 घंटे से' = for 3 hours (duration from past to now) → Present Perfect Continuous: has/have been + V-ing + for.", difficulty: "hard", marks: 2 },
  { id: 333, type: "mcq", question: "Which is correct: 'She is used to ___ early.'", options: ["wake", "to wake", "waking", "waked"], correct: "C", explanation: "'Be used to' (= accustomed to) + gerund (-ing). 'She is used to waking early' = she is accustomed to it. Different from 'used to' (past habit)!", difficulty: "hard", marks: 2 },
  { id: 334, type: "mcq", question: "Choose the correct sentence:", options: ["He suggested to go to the cinema.", "He suggested going to the cinema.", "He suggested that we to go to the cinema.", "He suggested us going to the cinema."], correct: "B", explanation: "'Suggest' + gerund (going) OR 'suggest + that + subject + base verb'. 'Suggest going' OR 'suggest that we go'. Never 'suggest to go'.", difficulty: "hard", marks: 2 },
  { id: 335, type: "mcq", question: "Which is correct: 'Despite ___ hard, he failed the exam.'", options: ["study", "studied", "studying", "to study"], correct: "C", explanation: "'Despite' + gerund (verb+ing) or noun. 'Despite studying hard...' = even though he studied. Never 'despite + to + verb'.", difficulty: "hard", marks: 2 },
  { id: 336, type: "translation", question: "Translate: 'मैं यहाँ 5 साल से रह रहा हूँ।'", options: ["I live here for 5 years.", "I am living here for 5 years.", "I have been living here for 5 years.", "I was living here for 5 years."], correct: "C", explanation: "Duration from past to present → Present Perfect Continuous: have been + V-ing + for. '5 साल से' = for 5 years.", difficulty: "hard", marks: 2 },
  { id: 337, type: "mcq", question: "Choose the correct conditional: 'If it rains, we ___ stay home.'", options: ["will", "would", "would have", "had"], correct: "A", explanation: "First conditional (real possibility): If + present simple, will + base verb. 'If it rains, we will stay home.' Real future possibility.", difficulty: "medium", marks: 1 },
  { id: 338, type: "mcq", question: "What type of adjective is 'this' in 'This book is mine'?", options: ["possessive", "demonstrative", "descriptive", "interrogative"], correct: "B", explanation: "'This, that, these, those' = demonstrative adjectives (when before a noun). 'This book' = demonstrative. 'This' alone = demonstrative pronoun.", difficulty: "medium", marks: 1 },
  { id: 339, type: "translation", question: "Translate: 'उन्होंने मुझे बताया कि वह बीमार है।'", options: ["They told me that they is sick.", "They told me that they are sick.", "They told me that they were sick.", "They tell me that they was sick."], correct: "C", explanation: "Reported speech / backshift: Direct: 'I am sick' → Indirect (past reporting verb): 'she/he was sick'. Main clause past → backshift.", difficulty: "hard", marks: 2 },
  { id: 340, type: "mcq", question: "Which is correct: 'I ___ rather stay home than go out.'", options: ["will", "would", "should", "could"], correct: "B", explanation: "'Would rather' + base verb = preference. 'I would rather stay' = I prefer to stay. 'Would rather' = I'd rather. Very common preference expression.", difficulty: "medium", marks: 1 },

  // ── PROFESSIONAL ENGLISH (341-370) ──────────────────────────
  { id: 341, type: "mcq", question: "Which is the most professional email opening?", options: ["Hey there!", "Dear Sir/Madam,", "What's up!", "Yo!"], correct: "B", explanation: "'Dear Sir/Madam' = formal professional opening for unknown recipient. 'Dear Mr./Ms. [Name]' = even better when you know the name.", difficulty: "easy", marks: 1 },
  { id: 342, type: "mcq", question: "What does 'FYI' stand for in professional emails?", options: ["Find Your Information", "For Your Information", "From Your Inbox", "Follow Your Instructions"], correct: "B", explanation: "FYI = For Your Information. Used to share information without requiring action. 'FYI, the meeting has been rescheduled.'", difficulty: "easy", marks: 1 },
  { id: 343, type: "mcq", question: "Which is the correct way to politely decline a meeting?", options: ["I can't come. Period.", "Unfortunately, I have a prior commitment at that time. Could we reschedule?", "No, I am busy.", "Sorry, I don't want to come."], correct: "B", explanation: "Professional decline: Acknowledge + Apologize + Reason + Alternative. 'Unfortunately I have a prior commitment' = polite, with an offer to reschedule.", difficulty: "medium", marks: 1 },
  { id: 344, type: "mcq", question: "What does 'ASAP' mean?", options: ["After Some Additional Planning", "As Soon As Possible", "A Standard And Practice", "All Systems Are Perfect"], correct: "B", explanation: "ASAP = As Soon As Possible. 'Please send the report ASAP.' = send it at the earliest opportunity.", difficulty: "easy", marks: 1 },
  { id: 345, type: "mcq", question: "Which email closing is most professional?", options: ["Yours truly, / Warm regards,", "See ya!", "Later!", "Bye bye,"], correct: "A", explanation: "Professional email closings: 'Yours sincerely', 'Best regards', 'Warm regards', 'Kind regards', 'Yours faithfully' (when you don't know the name).", difficulty: "easy", marks: 1 },
  { id: 346, type: "mcq", question: "In a meeting, which phrase politely disagrees?", options: ["You're wrong!", "That's stupid!", "I see your point, however I think...", "No, no, no!"], correct: "C", explanation: "'I see your point, however...' = acknowledge + disagree politely. Professional disagreement: validate first, then present your view.", difficulty: "easy", marks: 1 },
  { id: 347, type: "mcq", question: "What does 'EOD' mean in office communication?", options: ["End of December", "End of Day", "Either Or Decision", "Early Office Departure"], correct: "B", explanation: "EOD = End of Day. 'Please submit the report by EOD' = by end of today's working hours. Common office abbreviation.", difficulty: "easy", marks: 1 },
  { id: 348, type: "mcq", question: "Which phrase means 'to schedule a meeting'?", options: ["cancel a meeting", "set up a meeting", "skip a meeting", "end a meeting"], correct: "B", explanation: "'Set up a meeting' = schedule/arrange a meeting. 'Let's set up a meeting for next week.' Also: 'schedule a meeting', 'organize a meeting'.", difficulty: "easy", marks: 1 },
  { id: 349, type: "mcq", question: "Which is the correct way to request in an email?", options: ["Give me the report!", "I demand the report immediately.", "Could you please send me the report at your earliest convenience?", "Where is the report?"], correct: "C", explanation: "'Could you please' + request + 'at your earliest convenience' = polite, professional request formula. Politeness = professionalism.", difficulty: "easy", marks: 1 },
  { id: 350, type: "mcq", question: "What does 'take the minutes' mean in a meeting?", options: ["check the clock", "record what happens in a meeting", "leave the meeting early", "measure time"], correct: "B", explanation: "'Take the minutes' = officially write down what is discussed and decided in a meeting. The document is called 'minutes of the meeting'.", difficulty: "medium", marks: 1 },
  { id: 351, type: "mcq", question: "Which phrase means 'to review something quickly'?", options: ["deep dive into", "glance through", "thoroughly analyze", "ignore"], correct: "B", explanation: "'Glance through' = look at quickly/briefly. 'Deep dive into' = analyze thoroughly. Context determines which is appropriate.", difficulty: "medium", marks: 1 },
  { id: 352, type: "mcq", question: "What does 'loop someone in' mean in business English?", options: ["to exclude someone", "to include someone in a communication", "to fire someone", "to confuse someone"], correct: "B", explanation: "'Loop someone in' = include them in an email or conversation. 'Please loop me in on any updates' = keep me informed.", difficulty: "medium", marks: 1 },
  { id: 353, type: "mcq", question: "Which phrase means to contact someone again after an initial discussion?", options: ["ghost them", "follow up with them", "ignore them", "disagree with them"], correct: "B", explanation: "'Follow up' = contact again after initial contact. 'I'll follow up with you by end of week.' Very important professional communication skill.", difficulty: "easy", marks: 1 },
  { id: 354, type: "mcq", question: "What does 'benchmark' mean in business?", options: ["a piece of furniture", "a standard for comparison", "a type of accounting", "a new product"], correct: "B", explanation: "'Benchmark' = a standard or reference point for comparison. 'Our benchmark is competitor X's performance.' Used heavily in business.", difficulty: "medium", marks: 1 },
  { id: 355, type: "mcq", question: "Which phrase is used to summarize in a presentation?", options: ["Let's begin with", "To wrap up/In summary", "Moving on to", "That reminds me of"], correct: "B", explanation: "Presentation transitions: 'To begin' (opening), 'Moving on' (transition), 'To summarize/wrap up' (conclusion), 'That concludes' (ending).", difficulty: "easy", marks: 1 },
  { id: 356, type: "mcq", question: "What does 'touch base' mean?", options: ["play baseball", "contact briefly to share or check updates", "end a conversation", "start a new project"], correct: "B", explanation: "'Touch base' = make brief contact to share or receive updates. 'Let's touch base next Monday' = let's have a quick check-in.", difficulty: "medium", marks: 1 },
  { id: 357, type: "mcq", question: "In a job interview, when asked 'Tell me about yourself', you should:", options: ["share your entire life story", "give a professional summary of background, skills, and goals", "talk about your family", "say nothing personal"], correct: "B", explanation: "Interview answer formula: 1-2 mins: Current role/background + Key strengths + Why you're interested. Keep it professional and relevant.", difficulty: "medium", marks: 1 },
  { id: 358, type: "mcq", question: "What is the STAR method used for?", options: ["mathematics", "answering behavioral interview questions", "writing emails", "designing presentations"], correct: "B", explanation: "STAR = Situation, Task, Action, Result. Used to structure answers to behavioral questions: 'Tell me about a time when...'", difficulty: "medium", marks: 1 },
  { id: 359, type: "mcq", question: "Which is the correct way to ask for clarification?", options: ["What? Say it again!", "I didn't understand.", "Could you please clarify what you mean by...?", "That's confusing."], correct: "C", explanation: "'Could you please clarify...' = polite, professional request for clarification. Always acknowledge and ask specifically what you need clarified.", difficulty: "easy", marks: 1 },
  { id: 360, type: "mcq", question: "What does 'synergy' mean in business?", options: ["a type of software", "the interaction of combined effects greater than the sum of parts", "a salary increase", "a new product launch"], correct: "B", explanation: "'Synergy' = 1+1=3. When combined efforts produce greater results than individual efforts. Common in business mergers and team work.", difficulty: "hard", marks: 2 },

  // ── PRONUNCIATION & PHONICS (361-380) ───────────────────────
  { id: 361, type: "mcq", question: "Which word has a SILENT letter?", options: ["book", "climb", "table", "happy"], correct: "B", explanation: "'Climb' — the 'b' is silent. Other words with silent 'b': lamb, bomb, comb, thumb, debt, doubt, subtle.", difficulty: "medium", marks: 1 },
  { id: 362, type: "mcq", question: "Which word has a SILENT 'k'?", options: ["keep", "kite", "know", "kind"], correct: "C", explanation: "'Know' — the 'k' is silent. Silent 'k' before 'n': know, knock, knife, knight, knowledge, kneel, knot.", difficulty: "easy", marks: 1 },
  { id: 363, type: "mcq", question: "Which word has a SILENT 'w'?", options: ["wet", "write", "water", "win"], correct: "B", explanation: "'Write' — the 'w' is silent. Silent 'w' before 'r': write, wrong, wrap, wrist, wreck, wrestle.", difficulty: "easy", marks: 1 },
  { id: 364, type: "mcq", question: "In 'photograph', which syllable is stressed?", options: ["pho", "to", "graph", "Equal stress"], correct: "A", explanation: "'PHO-to-graph' — stress on first syllable. But 'pho-TO-graph-y' — stress on second! Word stress often shifts with suffixes.", difficulty: "hard", marks: 2 },
  { id: 365, type: "mcq", question: "Which word rhymes with 'cough'?", options: ["tough", "through", "off", "cow"], correct: "C", explanation: "'Cough' = /kɒf/. 'Off' = /ɒf/. They rhyme! English pronunciation is tricky — 'ough' has 8+ different sounds.", difficulty: "hard", marks: 2 },
  { id: 366, type: "mcq", question: "The 'th' in 'this' is pronounced like:", options: ["t", "voiced /ð/ (like in 'that')", "f", "s"], correct: "B", explanation: "'This, that, the, there, they, them, their, though' = voiced /ð/. 'Think, three, through, thank' = voiceless /θ/. Touch tongue to teeth!", difficulty: "hard", marks: 2 },
  { id: 367, type: "mcq", question: "Which word is NOT spelled phonetically?", options: ["cat", "put", "hat", "bed"], correct: "B", explanation: "'Put' — sounds like /pʊt/ (short u sound like 'book'), NOT /pʌt/ like 'but'. English pronunciation ≠ spelling often!", difficulty: "hard", marks: 2 },
  { id: 368, type: "mcq", question: "Which pair are MINIMAL PAIRS (same except one sound)?", options: ["cat/bat", "ship/sheep", "cat/hat", "both A and C"], correct: "D", explanation: "Minimal pairs differ in just ONE sound: cat/bat (initial sound), cat/hat (initial sound), ship/sheep (/ɪ/ vs /iː/). All are minimal pairs!", difficulty: "hard", marks: 2 },
  { id: 369, type: "mcq", question: "In 'present' (noun/adjective) vs 'present' (verb), where is the stress?", options: ["Both on first syllable", "Noun: PRE-sent, Verb: pre-SENT", "Both on second syllable", "Stress doesn't change"], correct: "B", explanation: "Stress shift: PRE-sent (noun/adj) vs pre-SENT (verb). Same pattern: REcord vs reCORD, PROtest vs proTEST, CONduct vs conDUCT.", difficulty: "hard", marks: 2 },
  { id: 370, type: "mcq", question: "The word 'colonel' is pronounced like:", options: ["kol-o-nel", "kur-nel", "col-o-nel", "col-nel"], correct: "B", explanation: "'Colonel' = /ˈkɜːrnəl/ = 'kernel'. One of the most irregularly pronounced English words. Historical French borrowing.", difficulty: "hard", marks: 2 },

  // ── READING COMPREHENSION (371-390) ─────────────────────────
  { id: 371, type: "comprehension", question: "Read: 'John works hard every day. He never misses a deadline. His manager always praises him.' What kind of employee is John?", options: ["lazy", "dedicated and reliable", "unreliable", "slow"], correct: "B", explanation: "Context clues: 'works hard', 'never misses a deadline', 'manager praises him' all indicate John is a dedicated, reliable, hardworking employee.", difficulty: "easy", marks: 1 },
  { id: 372, type: "comprehension", question: "Read: 'The market declined sharply. Several companies reported losses. Investors were worried.' What is the overall feeling?", options: ["optimistic", "neutral", "negative/pessimistic", "celebratory"], correct: "C", explanation: "'Declined', 'losses', 'worried' = all negative words. The overall tone is negative/pessimistic.", difficulty: "easy", marks: 1 },
  { id: 373, type: "comprehension", question: "Read: 'She practiced English daily for 75 days. On Day 75, she gave a speech to 500 people without hesitation.' What does this show?", options: ["English is impossible to learn", "Consistent daily practice leads to fluency", "She was naturally talented", "Public speaking is easy"], correct: "B", explanation: "The passage directly shows: consistent daily practice (75 days) → fluency (speech to 500 without hesitation). Cause and effect.", difficulty: "easy", marks: 1 },
  { id: 374, type: "comprehension", question: "Read: 'The product launch was well-received. Sales exceeded projections by 40%. Customer feedback was overwhelmingly positive.' What can we conclude?", options: ["The launch failed", "The launch was a great success", "Results were average", "There were complaints"], correct: "B", explanation: "'Well-received', 'exceeded projections by 40%', 'overwhelmingly positive' = all indicate a very successful product launch.", difficulty: "easy", marks: 1 },
  { id: 375, type: "comprehension", question: "Read: 'Despite studying for 10 hours, he failed the exam.' The word 'despite' shows:", options: ["cause and effect", "time sequence", "contrast/contradiction", "addition"], correct: "C", explanation: "'Despite' = although, even though. It shows contrast: studied a lot (cause) BUT failed (unexpected result). Contrast/concession.", difficulty: "medium", marks: 1 },
  { id: 376, type: "comprehension", question: "Read: 'The new policy requires all employees to report by 9 AM. Those who arrive late will face a penalty.' The tone is:", options: ["friendly", "directive/authoritative", "apologetic", "humorous"], correct: "B", explanation: "'Requires', 'will face a penalty' = directive, authoritative language. Not a suggestion — it's a rule.", difficulty: "medium", marks: 1 },
  { id: 377, type: "comprehension", question: "What is the main purpose of: 'Drink 8 glasses of water daily. Exercise for 30 minutes. Sleep 7-8 hours.'?", options: ["to entertain", "to give health advice", "to tell a story", "to describe a product"], correct: "B", explanation: "The passage gives health recommendations (drink water, exercise, sleep). Purpose: advisory/informational health guidance.", difficulty: "easy", marks: 1 },
  { id: 378, type: "comprehension", question: "Read: 'The meeting has been rescheduled from Monday to Wednesday.' What does this mean?", options: ["The meeting is cancelled", "The meeting is now on Wednesday", "The meeting is still on Monday", "There will be two meetings"], correct: "B", explanation: "'Rescheduled from Monday to Wednesday' = changed from Monday → now on Wednesday. 'Rescheduled' = moved to a different time.", difficulty: "easy", marks: 1 },
  { id: 379, type: "comprehension", question: "Read: 'He speaks English fluently. However, his written English needs improvement.' The word 'however' shows:", options: ["addition", "contrast", "cause", "result"], correct: "B", explanation: "'However' = but, on the other hand = shows contrast. Good at speaking (fact 1) HOWEVER written needs work (contrasting fact 2).", difficulty: "medium", marks: 1 },
  { id: 380, type: "comprehension", question: "Read: 'To apply, submit your CV, cover letter, and two references by 31st July.' What should you submit?", options: ["Just a CV", "CV + cover letter only", "CV + cover letter + two references", "References only"], correct: "C", explanation: "'Submit your CV, cover letter, AND two references' — 'and' joins all three. All three are required for the application.", difficulty: "easy", marks: 1 },

  // ── ADVANCED MIXED (381-400) ─────────────────────────────────
  { id: 381, type: "mcq", question: "Choose the correct: 'She ___ English for 5 years before she got the job.'", options: ["studied", "had studied", "has studied", "was studied"], correct: "B", explanation: "Past Perfect: action completed BEFORE another past action. 'Had studied' (before she got the job). 'Got' = past simple = reference point.", difficulty: "hard", marks: 2 },
  { id: 382, type: "mcq", question: "Which is correct: 'This is ___ than I expected.'", options: ["more easy", "easier", "more easier", "easiest"], correct: "B", explanation: "Short adjectives: add -er for comparative. 'Easy' → 'easier' (change y to i + er). 'More easier' = double comparative = wrong.", difficulty: "medium", marks: 1 },
  { id: 383, type: "translation", question: "Translate: 'उसने मुझसे कहा कि वह कल आएगा।'", options: ["He told me he will come tomorrow.", "He told me he would come the next day.", "He tells me he will come tomorrow.", "He said me he would come tomorrow."], correct: "B", explanation: "Reported speech: 'will' → 'would', 'tomorrow' → 'the next day', 'told me' (not 'said me'). Full backshift required.", difficulty: "hard", marks: 2 },
  { id: 384, type: "mcq", question: "Which phrase correctly shows purpose?", options: ["She studies hard therefore fluent.", "She studies hard in order to become fluent.", "She studies hard so become fluent.", "She studies hard becoming fluent."], correct: "B", explanation: "'In order to' + infinitive = purpose. Also: 'so that + clause', 'to + infinitive'. 'In order to become' = most formal way to express purpose.", difficulty: "medium", marks: 1 },
  { id: 385, type: "mcq", question: "Choose the correct: 'Not only ___ he speak English, but he also writes it well.'", options: ["do", "does", "is", "has"], correct: "B", explanation: "Emphatic inversion with 'Not only': Not only + auxiliary + subject + verb. 'Not only does he speak' = inverted for emphasis.", difficulty: "hard", marks: 2 },
  { id: 386, type: "mcq", question: "What is the gerund in: 'Swimming is my favorite exercise.'?", options: ["is", "swimming", "my", "exercise"], correct: "B", explanation: "'Swimming' = gerund (verb used as noun). It is the SUBJECT of the sentence. Gerunds end in -ing and function as nouns.", difficulty: "medium", marks: 1 },
  { id: 387, type: "mcq", question: "Choose the correct sentence:", options: ["I am interesting in this job.", "I am interested in this job.", "I am interesting about this job.", "I interest in this job."], correct: "B", explanation: "'Interested in' = how you feel. 'Interesting' = what causes interest. 'I am interested' (you feel it). 'The job is interesting' (it causes interest).", difficulty: "medium", marks: 1 },
  { id: 388, type: "mcq", question: "Which is the correct question tag?", options: ["She is your friend, isn't she?", "She is your friend, doesn't she?", "She is your friend, is she?", "She is your friend, wasn't she?"], correct: "A", explanation: "Question tag rule: positive statement → negative tag. 'She is...' → '...isn't she?' Use same tense and pronoun as main clause.", difficulty: "medium", marks: 1 },
  { id: 389, type: "mcq", question: "Choose the correct sentence with 'too' and 'enough':", options: ["The soup is hot enough to drink.", "The soup is too hot to drink.", "The soup is too enough hot.", "The soup too hot is to drink."], correct: "B", explanation: "'Too + adjective + to + verb' = negative consequence. 'Too hot to drink' = it's so hot you can't drink it. 'Enough' = sufficient. 'Hot enough' = sufficient temperature.", difficulty: "medium", marks: 1 },
  { id: 390, type: "translation", question: "Translate: 'काश मैंने पहले English सीखी होती!'", options: ["I wish I learned English before.", "I wish I had learned English earlier!", "I wish I learn English earlier!", "I hoped I had learned English before."], correct: "B", explanation: "'Wish' + past perfect = regret about past. 'Wish I had learned' = I didn't learn it earlier but wish I had. 'Earlier' = more natural than 'before' here.", difficulty: "hard", marks: 2 },

  // ── FINAL 10 (391-400) ───────────────────────────────────────
  { id: 391, type: "mcq", question: "Which word is a conjunction?", options: ["quickly", "beautiful", "although", "doctor"], correct: "C", explanation: "'Although' = subordinating conjunction (though, even though). Joins two clauses showing contrast.", difficulty: "easy", marks: 1 },
  { id: 392, type: "mcq", question: "Choose the correct form: 'The harder you work, ___ your chances of success.'", options: ["the better", "better", "the good", "good"], correct: "A", explanation: "Comparative: 'The more/harder..., the better/greater...' = parallel comparative structure. Both parts need 'the + comparative'.", difficulty: "hard", marks: 2 },
  { id: 393, type: "mcq", question: "What does 'miscellaneous' mean?", options: ["very serious", "consisting of various different kinds", "extremely expensive", "very common"], correct: "B", explanation: "'Miscellaneous' = various, mixed, diverse. 'Miscellaneous expenses' = various different types of expenses.", difficulty: "hard", marks: 2 },
  { id: 394, type: "fill-blank", question: "He is ___ honest that everyone trusts him. (so/such/very/too)", options: ["very", "such", "so", "too"], correct: "C", explanation: "'So + adjective + that' = result clause. 'He is so honest that everyone trusts him.' 'Such + noun/adj+noun + that': 'He is such an honest man that...'", difficulty: "hard", marks: 2 },
  { id: 395, type: "mcq", question: "Which is a correct use of 'latter'?", options: ["I have two options: work or study. The latter is better.", "Latter the day went well.", "The latter option is the first.", "I prefer the latter of the three."], correct: "A", explanation: "'Latter' = the second of two things mentioned. 'Former' = the first of two. 'Among three or more' = use 'last' not 'latter'.", difficulty: "hard", marks: 2 },
  { id: 396, type: "mcq", question: "What is the plural of 'criterion'?", options: ["criterions", "criteria", "criterias", "criterions"], correct: "B", explanation: "Latin origin: criterion → criteria. Other Latin plurals: datum → data, medium → media, phenomenon → phenomena, curriculum → curricula.", difficulty: "hard", marks: 2 },
  { id: 397, type: "mcq", question: "Choose the correct preposition: 'She arrived ___ the airport ___ time.'", options: ["at / in", "in / at", "at / on", "on / at"], correct: "C", explanation: "'Arrive at' specific locations (airport, station, school). 'On time' = punctual. 'She arrived at the airport on time.'", difficulty: "medium", marks: 1 },
  { id: 398, type: "mcq", question: "Which sentence uses the Oxford comma correctly?", options: ["I need eggs, bread and milk.", "I need eggs, bread, and milk.", "I need eggs bread, and milk.", "I need, eggs, bread, and milk."], correct: "B", explanation: "Oxford comma = comma before 'and' in a list: eggs, bread, AND milk. Helps avoid ambiguity. Standard in formal American English.", difficulty: "medium", marks: 1 },
  { id: 399, type: "mcq", question: "What is the difference between 'affect' and 'effect'?", options: ["No difference", "Affect = verb (to influence), Effect = noun (result)", "Effect = verb, Affect = noun", "Both are adjectives"], correct: "B", explanation: "RAVEN: Remember Affect Verb Effect Noun. 'Stress affects performance' (verb). 'Stress has a negative effect' (noun). Common confusion!", difficulty: "hard", marks: 2 },
  { id: 400, type: "mcq", question: "What does the phrase 'All that glitters is not gold' mean?", options: ["gold is very valuable", "shiny things are always gold", "things that look good are not always valuable or genuine", "all gold glitters"], correct: "C", explanation: "'All that glitters is not gold' = not everything that appears attractive is actually valuable. From Shakespeare's Merchant of Venice.", difficulty: "medium", marks: 1 },
];

